265	/** Cycle through the §16.4.1 location-line set on `Tab`. */
266	export function cycleWallLocationLine(current: WallLocationLine): WallLocationLine {
267	  const idx = WALL_LOCATION_LINE_ORDER.indexOf(current);
268	  if (idx < 0) return WALL_LOCATION_LINE_ORDER[0]!;
269	  return WALL_LOCATION_LINE_ORDER[(idx + 1) % WALL_LOCATION_LINE_ORDER.length]!;
270	}
