 1	import * as THREE from 'three';
 2	import type { Element } from '@bim-ai/core';
 3	
 4	export type WallElem = Extract<Element, { kind: 'wall' }>;
 5	
 6	/**
 7	 * Plan symbol for a curtain wall:
 8	 * - Thin center line
 9	 * - Short perpendicular tick marks for each grid division
10	 */
11	export function curtainWallPlanThree(wall: WallElem): THREE.Group {
12	  const group = new THREE.Group();
13	  group.userData.bimPickId = wall.id;
14	
15	  const sx = wall.start.xMm / 1000;
16	  const sz = wall.start.yMm / 1000;
17	  const ex = wall.end.xMm / 1000;
18	  const ez = wall.end.yMm / 1000;
19	  const len = Math.max(0.001, Math.hypot(ex - sx, ez - sz));
20	
21	  const dirX = (ex - sx) / len;
22	  const dirZ = (ez - sz) / len;
23	  const perpX = -dirZ;
24	  const perpZ = dirX;
25	
26	  const lineMat = new THREE.LineBasicMaterial({ color: 0x222222, linewidth: 1 });
27	
28	  // Main center line
29	  const mainPts = [new THREE.Vector3(sx, 0, sz), new THREE.Vector3(ex, 0, ez)];
30	  group.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(mainPts), lineMat));
31	
32	  // Vertical grid divisions (V grid = divisions along the wall length)
33	  const vCount = wall.curtainWallData?.gridV?.count ?? wall.curtainWallVCount ?? 0;
34	  const tickLen = 0.1; // 100mm tick
35	  if (vCount > 0) {
36	    const step = len / vCount;
37	    for (let i = 1; i < vCount; i++) {
38	      const t = i * step;
39	      const tx = sx + t * dirX;
40	      const tz = sz + t * dirZ;
41	      const tickMat = new THREE.LineBasicMaterial({ color: 0x444444 });
42	      const tickPts = [
43	        new THREE.Vector3(tx - (perpX * tickLen) / 2, 0, tz - (perpZ * tickLen) / 2),
44	        new THREE.Vector3(tx + (perpX * tickLen) / 2, 0, tz + (perpZ * tickLen) / 2),
45	      ];
46	      group.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(tickPts), tickMat));
47	    }
48	  }
49	
50	  return group;
51	}

