/* ────────────────────────────────────────────────────────────────────── */
/* WP-C C1 — Attach Top/Base tool grammar                               */
/*                                                                        */
/* idle → click-wall → picking-target                                     */
/* picking-target → click-target (roof|floor|ceiling) → idle + effect    */
/* picking-target → cancel/deactivate → idle                             */
/* ────────────────────────────────────────────────────────────────────── */

export type AttachState = { phase: 'idle' } | { phase: 'picking-target'; wallId: string };

export type AttachEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'cancel' }
  | { kind: 'click'; elementId: string; elementKind: string };

export interface AttachEffect {
  attachWallTop?: { wallId: string; targetId: string };
  stillActive: boolean;
}

export function initialAttachState(): AttachState {
  return { phase: 'idle' };
}

const ATTACH_TARGET_KINDS = new Set(['roof', 'floor', 'ceiling']);

export function reduceAttach(
  state: AttachState,
  event: AttachEvent,
): { state: AttachState; effect: AttachEffect } {
  if (event.kind === 'activate') {
    return { state: { phase: 'idle' }, effect: { stillActive: true } };
  }
  if (event.kind === 'deactivate') {
    return { state: { phase: 'idle' }, effect: { stillActive: false } };
  }
  if (event.kind === 'cancel') {
    return { state: { phase: 'idle' }, effect: { stillActive: true } };
  }
  if (event.kind === 'click') {
    if (state.phase === 'idle' && event.elementKind === 'wall') {
      return {
        state: { phase: 'picking-target', wallId: event.elementId },
        effect: { stillActive: true },
      };
    }
    if (state.phase === 'picking-target' && ATTACH_TARGET_KINDS.has(event.elementKind)) {
      return {
        state: { phase: 'idle' },
        effect: {
          attachWallTop: { wallId: state.wallId, targetId: event.elementId },
          stillActive: true,
        },
      };
    }
  }
  return { state, effect: { stillActive: true } };
}

/* ────────────────────────────────────────────────────────────────────── */
/* WP-C C1 — Detach tool grammar                                         */
/*                                                                        */
/* idle → click-wall → idle + effect                                      */
/* ────────────────────────────────────────────────────────────────────── */

export type DetachState = { phase: 'idle' };

export type DetachEvent =
  | { kind: 'activate' }
  | { kind: 'deactivate' }
  | { kind: 'cancel' }
  | { kind: 'click'; elementId: string; elementKind: string };

export interface DetachEffect {
  detachWallTop?: { wallId: string };
  stillActive: boolean;
}

export function initialDetachState(): DetachState {
  return { phase: 'idle' };
}

export function reduceDetach(
  state: DetachState,
  event: DetachEvent,
): { state: DetachState; effect: DetachEffect } {
  if (event.kind === 'activate') {
    return { state: { phase: 'idle' }, effect: { stillActive: true } };
  }
  if (event.kind === 'deactivate') {
    return { state: { phase: 'idle' }, effect: { stillActive: false } };
  }
  if (event.kind === 'cancel') {
    return { state: { phase: 'idle' }, effect: { stillActive: false } };
  }
  if (event.kind === 'click' && event.elementKind === 'wall') {
    return {
      state: { phase: 'idle' },
      effect: { detachWallTop: { wallId: event.elementId }, stillActive: true },
    };
  }
  return { state, effect: { stillActive: true } };
}

